{
  "global": "Compute polynomial derivatives by applying the power rule: multiply each coefficient xs[i] by its power i and return the transformed coefficients.",
  "subtasks": [
    {
      "subtask": "Recognize the input representation and drop the constant term",
      "atomics": [
        "Understand that xs[i] is the coefficient of x^i in the polynomial xs[0] + xs[1]*x + xs[2]*x^2 + ...",
        "Recognize that the derivative of xs[0] (constant) is zero, so this coefficient is omitted from output"
      ]
    },
    {
      "subtask": "Apply the power rule of differentiation to remaining coefficients",
      "atomics": [
        "For each coefficient xs[i] at position i >= 1, multiply by i to get i * xs[i]",
        "This transformation gives the correct coefficient of x^(i-1) in the derivative polynomial"
      ]
    },
    {
      "subtask": "Assemble the result list in correct order",
      "atomics": [
        "Collect all scaled coefficients: [1*xs[1], 2*xs[2], 3*xs[3], ..., (n)*xs[n]]",
        "Return this ordered list as the derivative polynomial coefficients"
      ]
    }
  ],
  "global_atomics": [
    "Verify output length equals max(0, len(xs) - 1)",
    "Test against provided examples: [3,1,2,4,5]→[1,4,12,20] and [1,2,3]→[2,6]"
  ],
  "gold_actions": {
    "global": "Return the list [i * xs[i] for i in range(1, len(xs))].",
    "subtasks": [
      {
        "subtask": "Identify the skip-constant pattern and scaling index correspondence",
        "atomics": [
          "Skip xs[0]; the power rule derivative of a constant is zero",
          "Map each xs[i] to index i, which is the power exponent in the original polynomial"
        ]
      },
      {
        "subtask": "Compute scaled coefficients using the power rule formula",
        "atomics": [
          "Compute 1*xs[1], 2*xs[2], 3*xs[3], ..., (len(xs)-1)*xs[len(xs)-1]",
          "Use list comprehension or enumerate to apply i * xs[i] for all i in range(1, len(xs))"
        ]
      },
      {
        "subtask": "Construct and return the derivative coefficient list",
        "atomics": [
          "Form result = [i * xs[i] for i in range(1, len(xs))]",
          "Return result as the final derivative polynomial coefficients"
        ]
      }
    ],
    "global_atomics": [
      "Assert that len(result) == len(xs) - 1 when len(xs) > 0; return [] if len(xs) <= 1",
      "Verify derivative([3,1,2,4,5]) produces [1,4,12,20] and derivative([1,2,3]) produces [2,6]"
    ]
  }
}
